    llvm::errs() << "InstCombine: matched or disjoint (shl (udiv V, C), Shift), (urem V, C)\n";
    // Compute B = 1 << ShiftAmt
    if (ShiftAmt->uge(ShiftAmt->getBitWidth()))
      return nullptr;
    APInt BVal = APInt::getOneBitSet(ShiftAmt->getBitWidth(), ShiftAmt->getZExtValue());
    APInt BMinusC = BVal - *DivC;
    if (BMinusC.isZero())
      return replaceInstUsesWith(I, V);
    Value *Mul = Builder.CreateMul(UDiv, ConstantInt::get(Ty, BMinusC));
    return BinaryOperator::CreateAdd(V, Mul);
